Overall, the trend indicates steady demand for outpatient care."},{"type":"figure","presentationObjectInReportInfo":{"id":"cea6db4b-2e42-401e-9a41-2621a6df5543","moduleId":"m003","isDefault":false,"selectedReplicantValue":""},"stretch":true,"fillArea":false,"textSize":1,"textBackground":"none","placeholderInvisible":false,"placeholderStretch":true,"placeholderHeight":50,"useFigureAdditionalScale":false,"figureAdditionalScale":1,"imgHeight":300,"imgFit":"inside","imgStretch":true,"hideFigureCaption":false,"hideFigureSubCaption":false,"hideFigureFootnote":false}]],"useHeader":true,"headerText":"Trends in outpatient visits"}}

